#include<bits/stdc++.h>
using namespace std;
set<long long> s;
long long a[200010],n,q,c;
int main()
{
    scanf("%lld%lld%lld",&n,&q,&c);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
        if(i==1||a[*s.rbegin()]<a[i])
        {
            s.insert(i);
        }
    }
    long long lstans=0;
    while(q--)
    {
        long long x,v;
        scanf("%lld%lld",&x,&v);
        x^=c*(lstans%3);
        a[x]+=v;
        if(a[*(--s.upper_bound(x))]>a[x])
        {
            printf("%lld\n",lstans=(long long)(s.size()));
            continue;
        }
        s.insert(x);
        while(s.upper_bound(x)!=s.end()&&a[*s.upper_bound(x)]<a[x])
        {
            s.erase(s.upper_bound(x));
        }
        printf("%lld\n",lstans=(long long)(s.size()));
    }
    return 0;
}
